import os
import json
import time
import shutil

class DiskCache:
    def __init__(self, cache_dir, default_expiration_seconds=3600):
        self.cache_dir = cache_dir
        self.default_expiration_seconds = default_expiration_seconds
        os.makedirs(self.cache_dir, exist_ok=True)

    def _get_cache_filepath(self, key):
        # Simple hashing for filename, adjust if keys can be very long or have special chars
        return os.path.join(self.cache_dir, f"{hash(key)}.json")

    def set(self, key, data, expiration_seconds=None):
        filepath = self._get_cache_filepath(key)
        expiration_time = time.time() + (expiration_seconds if expiration_seconds is not None else self.default_expiration_seconds)
        
        cache_entry = {
            "data": data,
            "expires_at": expiration_time
        }
        
        try:
            with open(filepath, 'w', encoding='utf-8') as f:
                json.dump(cache_entry, f, ensure_ascii=False, indent=None, separators=(',', ':')) # Compact JSON
        except Exception as e:
            print(f"Error writing cache for key {key}: {e}")
            # Optionally clean up partial file
            if os.path.exists(filepath):
                os.remove(filepath)

    def get(self, key):
        filepath = self._get_cache_filepath(key)
        
        if not os.path.exists(filepath):
            return None

        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                cache_entry = json.load(f)
            
            if cache_entry["expires_at"] < time.time():
                # Cache expired, remove it
                os.remove(filepath)
                return None
            
            return cache_entry["data"]
        except (json.JSONDecodeError, KeyError, FileNotFoundError) as e:
            print(f"Error reading or parsing cache for key {key}: {e}")
            # Corrupted or malformed cache file, remove it
            if os.path.exists(filepath):
                os.remove(filepath)
            return None
        except Exception as e:
            print(f"Unexpected error getting cache for key {key}: {e}")
            return None

    def delete(self, key):
        filepath = self._get_cache_filepath(key)
        if os.path.exists(filepath):
            try:
                os.remove(filepath)
                return True
            except Exception as e:
                print(f"Error deleting cache for key {key}: {e}")
                return False
        return False

    def clear(self):
        """Clears all items from the cache."""
        try:
            shutil.rmtree(self.cache_dir)
            os.makedirs(self.cache_dir, exist_ok=True)
            return True
        except Exception as e:
            print(f"Error clearing cache directory {self.cache_dir}: {e}")
            return False

    def cleanup_expired(self):
        """Iterates through all cache files and removes expired ones."""
        now = time.time()
        for filename in os.listdir(self.cache_dir):
            if not filename.endswith('.json'):
                continue
            filepath = os.path.join(self.cache_dir, filename)
            try:
                with open(filepath, 'r', encoding='utf-8') as f:
                    cache_entry = json.load(f)
                
                if cache_entry["expires_at"] < now:
                    os.remove(filepath)
            except (json.JSONDecodeError, KeyError, FileNotFoundError) as e:
                print(f"Error cleaning up malformed cache file {filepath}: {e}. Removing it.")
                if os.path.exists(filepath):
                    os.remove(filepath)
            except Exception as e:
                print(f"Unexpected error during cleanup for file {filepath}: {e}")